const fn variant_names() -> [&'static str; 197] {
    let mut names = [""; 197];
    let mut index = 0;
    while index < CHAIN_DATA.len() {
        names[index] = CHAIN_DATA[index].name.get_unchecked();
        index += 1;
    }
    names
}

